const TRUSTED_SOURCES = [
  'sicredi.com.br','sicoob.com.br','bancoob.com.br','unicred.com.br',
  'unimed.com.br','coamo.com.br','cocamar.com.br','ocb.org.br',
  'inova.coop.br','mundocoop.com.br','celcoin.com.br','woccu.org',
  'meioemensagem.com.br','b9.com.br','exame.com','nexojornal.com.br'
];
const COOP_KEYWORDS = [
  'cooperativa','cooperativismo','cooperado','sicredi','sicoob',
  'unimed','ocb','sobras','governança cooperativa','marketing cooperativo',
  'ia cooperativa','fintech cooperativa','open finance cooperativa'
];
const BLOCKED = ['assessoria','press release','nota oficial','comunicado de imprensa'];

const news = $input.all()[0].json.news || [];
const scored = [];

for (const item of news) {
  let score = 0.5;
  const url = (item.link || '').toLowerCase();
  const combined = ((item.title || '') + ' ' + (item.snippet || '')).toLowerCase();

  if (TRUSTED_SOURCES.some(s => url.includes(s))) score += 0.2;
  const kwMatches = COOP_KEYWORDS.filter(kw => combined.includes(kw)).length;
  score += Math.min(kwMatches * 0.05, 0.15);
  if (BLOCKED.some(p => combined.includes(p))) score -= 0.3;
  const hoursOld = (Date.now() - new Date(item.date || Date.now()).getTime()) / 3600000;
  if (hoursOld <= 24) score += 0.1;

  let vertical = 'geral';
  if (combined.match(/sicredi|sicoob|unicred|crédito|fintech|open finance/)) vertical = 'credito';
  else if (combined.match(/agro|coamo|cocamar|produtor rural/)) vertical = 'agro';
  else if (combined.match(/unimed|saúde|médico cooperado/)) vertical = 'saude';
  else if (combined.match(/consumo|habitação|varejo cooperativa/)) vertical = 'consumo';

  score = Math.min(Math.max(parseFloat(score.toFixed(2)), 0), 1);
  if (score >= 0.75) {
    scored.push({ json: { title: item.title, link: item.link, snippet: item.snippet, source: item.source, date: item.date, source_score: score, vertical } });
  }
}
scored.sort((a, b) => b.json.source_score - a.json.source_score);
return scored.slice(0, 3);

