// === GATEKEEPER — Briefing.Co (fa.md V3.1) ===
const item = $input.item;
const content = item.json.message?.content || '';
const scoutData = item.json;

const BANNED = ['disruptivo','disruptiva','sinergia','alavancar','alavancagem',
  'pensar fora da caixa','ecossistema','inovar','inovação disruptiva',
  'agregar valor','estado da arte'];

const checks = {};

// 1 — Densidade (Radar ≥ 2.000 chars)
checks.density = { passed: content.length >= 2000, detail: `${content.length} chars (mín: 2000)` };

// 2 — Glossário Banido
const found = BANNED.filter(w => content.toLowerCase().includes(w));
checks.banned_words = { passed: found.length === 0, detail: found.length ? `Banidas: ${found.join(', ')}` : 'OK' };

// 3 — Substância mínima
const hasSubstance = content.toLowerCase().includes('cooperativa') &&
  (content.toLowerCase().includes('gestor') || content.toLowerCase().includes('impacto'));
checks.cmad = { passed: hasSubstance && content.length >= 2000, detail: hasSubstance ? 'Substância presente' : 'Falta análise de impacto' };

// 4 — Vantagem Injusta
const hasVI = content.toLowerCase().includes('vantagem injusta') ||
  content.toLowerCase().includes('o gestor pode') || content.toLowerCase().includes('o que fazer');
checks.unfair_advantage = { passed: hasVI, detail: hasVI ? 'Presente' : 'FALTA seção Vantagem Injusta' };

// 5 — Anti-Jabá (Teste do Orfanato)
const brands = (content.match(/sicredi|sicoob|unimed|banrisul|itaú|bradesco/gi) || []).length;
const paragraphs = Math.max(1, (content.match(/\n\n/g) || []).length);
const ratio = brands / paragraphs;
checks.anti_jaba = { passed: ratio < 0.8, detail: ratio < 0.8 ? 'Independente de marca' : `JABÁ: ${brands} marcas em ${paragraphs} parágrafos` };

const allPassed = Object.values(checks).every(c => c.passed);
const failedList = Object.entries(checks).filter(([,v]) => !v.passed).map(([k,v]) => `${k}: ${v.detail}`);

return { json: {
  content,
  gatekeeper_passed: allPassed,
  output_score: allPassed ? 0.92 : 0.40,
  checks,
  failed_checks: failedList,
  vertical: scoutData.vertical || 'geral',
  source_url: scoutData.link || '',
  source_name: scoutData.source || '',
  source_score: scoutData.source_score || 0
}};

const content = $json.content || '';
const headlineMatch = content.match(/##\s*(.+)/);
const headline = headlineMatch ? headlineMatch[1].trim().replace(/[*_]/g,'') : 'Radar Cooperativo';
const leadMatch = content.match(/\*\*O que aconteceu:\*\*\s*(.+)/);
const lead = leadMatch ? leadMatch[1].trim() : '';
const tldrMatch = content.match(/\*\*TL;DR:\*\*([\s\S]+)$/);
const tldr = tldrMatch ? tldrMatch[1].trim() : '';
const slug = headline.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9\s-]/g,'').replace(/\s+/g,'-').slice(0,80);
const wordCount = content.split(/\s+/).length;
const readingTime = Math.max(1, Math.ceil(wordCount / 300));
return { json: {
  slug: `${slug}-${Date.now()}`,
  title: headline, lead, content, tldr,
  caderno: 'radar', access_level: 'free',
  vertical: $json.vertical || 'geral',
  source_url: $json.source_url || '',
  source_name: $json.source_name || '',
  source_score: $json.source_score || 0,
  output_score: $json.output_score || 0,
  reading_time_min: readingTime,
  status: 'published',
  published_at: new Date().toISOString(),
  created_by: 'crew-radar-n8n'
}};

